INSERT INTO questions (id, topic_id, type, prompt, explanation, difficulty_level, sort_order, created_at, updated_at) VALUES
('00000000-0000-0000-0000-000000000301', '00000000-0000-0000-0000-000000000203', 'MULTIPLE_CHOICE', 'What is 4 + 3?', '4 plus 3 equals 7.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000302', '00000000-0000-0000-0000-000000000203', 'MULTIPLE_CHOICE', 'What is 6 + 2?', '6 plus 2 equals 8.', 1, 2, NOW(), NOW()),
('00000000-0000-0000-0000-000000000303', '00000000-0000-0000-0000-000000000204', 'MULTIPLE_CHOICE', 'What is 9 - 4?', '9 minus 4 equals 5.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000304', '00000000-0000-0000-0000-000000000204', 'MULTIPLE_CHOICE', 'What is 7 - 3?', '7 minus 3 equals 4.', 1, 2, NOW(), NOW()),
('00000000-0000-0000-0000-000000000305', '00000000-0000-0000-0000-000000000205', 'MULTIPLE_CHOICE', 'Which comes next: 2, 4, 6, ?', 'The pattern adds 2 each time, so the next number is 8.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000306', '00000000-0000-0000-0000-000000000208', 'MULTIPLE_CHOICE', 'How many syllables are in "banana"?', 'Ba-na-na has 3 syllables.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000307', '00000000-0000-0000-0000-000000000209', 'MULTIPLE_CHOICE', 'Complete: The cat is ___ the mat.', 'The sentence is completed with "on".', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000308', '00000000-0000-0000-0000-000000000210', 'MULTIPLE_CHOICE', 'What is the opposite of big?', 'The opposite of big is small.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000309', '00000000-0000-0000-0000-000000000206', 'MULTIPLE_CHOICE', 'Which letter says /m/?', 'The sound /m/ is represented by the letter M.', 1, 1, NOW(), NOW()),
('00000000-0000-0000-0000-000000000310', '00000000-0000-0000-0000-000000000207', 'MULTIPLE_CHOICE', 'Which one is a vowel?', 'A, E, I, O and U are vowels.', 1, 1, NOW(), NOW());
